Method.Source:
/// <summary>
///
/// </summary>
/// <param name="_sender"></param>
/// <param name="_eventArgs"></param>
[DataEventHandler(tableStr(VendProductReceiptLineV2Entity), DataEventType::PostedLoad)]
public static void VendProductReceiptLineV2Entity_onPostedLoad(Common _sender, DataEventArgs _eventArgs)
{
    VendProductReceiptLineV2Entity vendProductReceiptLineV2Entity = _sender as VendProductReceiptLineV2Entity;
    InventTable inventTable;
    VendPackingSlipJour vendPackingSlipJour;

    PurchTable purchTable;
    PurchAgreementHeader purchAgreementHeader;

    select * from inventTable 
        where inventTable.ItemId == vendProductReceiptLineV2Entity.ItemNumber;

    vendProductReceiptLineV2Entity.ETGMainCommodity = inventTable.ETGCommodity;

    select * from vendPackingSlipJour
        where vendPackingSlipJour.RecId == vendProductReceiptLineV2Entity.VendPackingSlipJour;

    vendProductReceiptLineV2Entity.VendorName = vendPackingSlipJour.vendName();
    vendProductReceiptLineV2Entity.VendorAddress = vendPackingSlipJour.vendAddress();

    select * from purchTable
        where purchTable.PurchId == vendProductReceiptLineV2Entity.PurchaseOrderNumber;

    select * from purchAgreementHeader
        where purchAgreementHeader.RecId == purchTable.MatchingAgreement;

    vendProductReceiptLineV2Entity.ETGPurchaseAgreementId = purchAgreementHeader.PurchNumberSequence;

}
